<?php
namespace App\Http\Controllers\Inventory; use App\Http\Controllers\Controller; use App\Models\Inventory\{InventoryBalance,InventoryCategory,InventoryCondition,InventoryLocation,InventoryTransaction}; use Illuminate\Http\Request; use Symfony\Component\HttpFoundation\StreamedResponse;
class InventoryReportController extends Controller{public function index(Request $r){$balances=$this->balances($r)->paginate(50); return view('inventory.reports.index',['balances'=>$balances,'categories'=>InventoryCategory::get(),'locations'=>InventoryLocation::get(),'conditions'=>InventoryCondition::get(),'transactions'=>InventoryTransaction::with('item')->latest()->limit(20)->get()]);} public function print(Request $r){return view('inventory.reports.print',['balances'=>$this->balances($r)->get(),'printedAt'=>now(),'filters'=>$r->query()]);} public function pdf(Request $r){return response($this->print($r)->render(),200,['Content-Type'=>'application/pdf','Content-Disposition'=>'attachment; filename="laporan-inventaris.pdf"']);} public function export(Request $r):StreamedResponse{return response()->streamDownload(function()use($r){$f=fopen('php://output','w'); fprintf($f, chr(0xEF).chr(0xBB).chr(0xBF)); fputcsv($f,['Kode Barang','Nama Barang','Kategori','Lokasi','Kondisi','Jumlah','Nilai Perolehan']); $this->balances($r)->chunk(200,function($rows)use($f){foreach($rows as $b)fputcsv($f,[$b->item->code,$b->item->name,$b->item->category?->name,$b->location?->name,$b->condition?->name,$b->quantity,$b->item->acquisition_value]);}); fclose($f);},'laporan-inventaris-'.now()->format('Ymd-His').'.csv',['Content-Type'=>'text/csv; charset=UTF-8']);} private function balances(Request $r){return InventoryBalance::with('item.category','location','condition')->whereHas('item',fn($q)=>$q->when($r->category_id,fn($x)=>$x->where('inventory_category_id',$r->category_id))->when($r->status!==null&&$r->status!=='',fn($x)=>$x->where('is_active',(bool)$r->status)))->when($r->location_id,fn($q)=>$q->where('inventory_location_id',$r->location_id))->when($r->condition_id,fn($q)=>$q->where('inventory_condition_id',$r->condition_id));}}
